{
  "recipes": [
    {
      "name": "Authentic Sichuan Mapo Tofu",
      "instructions": [
        "Cut the silken tofu into 2cm cubes. Gently blanch in salted boiling water for 1 minute to firm up, then drain carefully.",
        "Finely mince the garlic and ginger.",
        "Heat oil in a wok over medium heat. Add the minced beef and stir-fry until browned and crispy.",
        "Add the Pixian Doubanjiang and stir-fry until the oil turns a rich red color.",
        "Stir in the minced garlic and ginger, cooking until fragrant.",
        "Pour in the chicken broth, Shaoxing rice wine, and light soy sauce. Bring to a gentle simmer.",
        "Carefully slide in the tofu cubes. Simmer for 5 minutes to allow the flavors to penetrate the tofu.",
        "Gradually pour in the cornstarch slurry in three stages, stirring gently to thicken the sauce without breaking the tofu.",
        "Transfer to a serving bowl and generously sprinkle with ground Sichuan peppercorns and chopped spring onions."
      ],
      "required_ingredients": [
        {
          "name": "silken tofu",
          "amount": "400g"
        },
        {
          "name": "minced beef",
          "amount": "100g"
        },
        {
          "name": "garlic",
          "amount": "3 cloves"
        },
        {
          "name": "ginger",
          "amount": "15g"
        },
