          "amount": "2 tbsp"
        },
        {
          "name": "chili oil",
          "amount": "2 tbsp"
        },
        {
          "name": "Sichuan pepper oil",
          "amount": "1 tsp"
        },
        {
          "name": "toasted sesame seeds",
          "amount": "1 tsp"
        },
        {
          "name": "spring onions",
          "amount": "1 stalk"
        }
      ],
      "missing_ingredients": [
        "Light Soy Sauce (approx. £1.50)",
        "Chili Oil (approx. £2.50)",
        "Sichuan Pepper Oil (approx. £2.80)",
        "Toasted Sesame Seeds (approx. £1.20)",
        "Spring Onions (approx. £0.60)"
      ]
    },
    {
      "name": "Sichuan Spicy Beef and Tofu Stew",
      "instructions": [
        "Cut the silken tofu into large, thick cubes. Mince the garlic and ginger.",
        "In a deep pot, heat oil over medium heat. Fry the garlic, ginger, and Sichuan hot pot base until fragrant and red oil forms.",
        "Add the minced beef and stir-fry until cooked through.",
        "Pour in the chicken stock and bring the soup to a boil.",
        "Gently slide in the tofu cubes. Reduce the heat and simmer gently for 10 minutes to let the tofu absorb the spicy broth.",
        "Drizzle with soy sauce, stir in a light cornstarch slurry to slightly thicken the stew, and garnish with fresh cilantro."
      ],
      "required_ingredients": [
        {
          "name": "silken tofu",
          "amount": "300g"
        },
        {
          "name": "minced beef",
          "amount": "150g"
        },
        {
          "name": "garlic",
          "amount": "4 cloves"
        },
        {
          "name": "ginger",
          "amount": "15g"
        },
        {
          "name": "Sichuan hot pot base",
          "amount": "2 tbsp"
        },
        {
          "name": "chicken stock",
          "amount": "500ml"
        },
        {
          "name": "light soy sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "cornstarch",
          "amount": "1 tsp"
        },
        {
          "name": "fresh cilantro",
          "amount": "to taste"
        }
      ],
      "missing_ingredients": [
        "Sichuan Hot Pot Base (approx. £3.50 in London Chinese supermarkets)",
        "Chicken Stock (approx. £1.20)",
        "Light Soy Sauce (approx. £1.50)",
        "Cornstarch (approx. £1.00)",
        "Fresh Cilantro (approx. £0.80)"
      ]
    }
  ]
}

{
  "recipes": [
    {
      "name": "Gong Bao Ji Ding (Sichuan Kung Pao Chicken)",
      "instructions": [
        "Cut the chicken breasts into 1.5cm cubes. Marinate with a splash of soy sauce, Shaoxing wine, and cornstarch for 15 minutes.",
        "Cut the spring onions into white and green rounds. Prepare the sauce by mixing black vinegar, soy sauce, sugar, a little water, cornstarch, and 1 tbsp of peanut butter (melted) to mimic the traditional nutty depth.",
        "Heat oil in a wok over medium heat. Fry dried chilies and Sichuan peppercorns until fragrant and darkened.",
        "Add the chicken cubes and stir-fry on high heat until cooked through and slightly browned.",
        "Add garlic, ginger, and the spring onion whites, stir-frying for 1 minute.",
        "Pour in the prepared sauce, stirring quickly until it thickens into a glossy glaze.",
        "Toss in the spring onion greens and roasted peanuts (if available), then serve hot."
