{
  "recipes": [
    {
      "name": "Shanghai Style Red Braised Pork (Hong Shao Rou)",
      "instructions": [
        "Cut the pork belly into 2cm cubes. Blanch in boiling water with a few slices of ginger for 5 minutes, then drain and rinse.",
        "In a wok or heavy pot, heat 1 tbsp of oil and add the rock sugar over low heat, stirring constantly until melted and amber-colored.",
        "Add the pork belly to the caramelized sugar, stirring quickly to coat the meat evenly.",
        "Add sliced ginger, bruised garlic cloves, Shaoxing rice wine, light soy sauce, and dark soy sauce. Pour in enough boiling water to just cover the meat.",
        "Bring to a boil, then cover and simmer on low heat for 45-50 minutes until the pork is tender.",
        "Remove the lid, turn up the heat to high, and reduce the sauce until it is thick, glossy, and clings to the pork."
      ],
      "required_ingredients": [
        {
          "name": "Pork belly",
          "amount": "500g"
